import 'package:flutter/material.dart';
import 'package:flutter_bloc/flutter_bloc.dart';
import 'package:get/get.dart';

// BLoC implementation
class CounterCubit extends Cubit<int> {
  CounterCubit() : super(0);
  void increment() => emit(state + 1);
}

// GetX controller
class CounterController extends GetxController {
  var count = 0.obs;
  void increment() => count++;
}

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'BLoC vs GetX',
      home: DefaultTabController(
        length: 2,
        child: Scaffold(
          appBar: AppBar(
            title: Text('BLoC vs GetX'),
            bottom: TabBar(
              tabs: [
                Tab(text: 'BLoC'),
                Tab(text: 'GetX'),
              ],
            ),
          ),
          body: TabBarView(
            children: [
              BlocProvider(
                create: (_) => CounterCubit(),
                child: BlocPage(),
              ),
              GetXPage(),
            ],
          ),
        ),
      ),
    );
  }
}

class BlocPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Center(
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Text('BLoC Counter', style: TextStyle(fontSize: 20)),
          BlocBuilder<CounterCubit, int>(
            builder: (context, state) => Text('$state', style: TextStyle(fontSize: 40)),
          ),
          ElevatedButton(
            onPressed: () => context.read<CounterCubit>().increment(),
            child: Text('Increment'),
          ),
        ],
      ),
    );
  }
}

class GetXPage extends StatelessWidget {
  final CounterController controller = Get.put(CounterController());

  @override
  Widget build(BuildContext context) {
    return Center(
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Text('GetX Counter', style: TextStyle(fontSize: 20)),
          Obx(() => Text('${controller.count}', style: TextStyle(fontSize: 40))),
          ElevatedButton(
            onPressed: controller.increment,
            child: Text('Increment'),
          ),
        ],
      ),
    );
  }
}
